/* ============================================================
   Burger Nav — mobile-first multilevel menu
   Desktop: horizontal nav, click-to-open dropdown (no hover).
   Mobile (<768px): slide-in drawer, accordion submenus.
   ============================================================ */

/* ── Wrapper ─────────────────────────────────────────────── */
.cms-widget--menu {
  display: flex;
  align-items: center;
  justify-content: space-between;
  padding: 0 1.5rem;
  min-height: 56px;
  position: relative;
  z-index: 200;
}

/* ── Desktop: horizontal row ─────────────────────────────── */
.cms-menu {
  display: flex;
  flex-direction: row;
  align-items: center;
  padding: 0;
  margin: 0;
}

.cms-menu__item {
  position: relative;
}

.cms-menu__link {
  display: flex;
  align-items: center;
  gap: 0.3rem;
  padding: 0.6rem 1rem;
  color: inherit;
  text-decoration: none;
  font-weight: 500;
  font-size: 0.95rem;
  white-space: nowrap;
  transition: color 0.15s;
  cursor: pointer;
  user-select: none;
}

.cms-menu__link:hover {
  color: var(--color-primary, #2563eb);
}

.cms-menu__arrow {
  font-size: 0.7rem;
  opacity: 0.55;
  transition: transform 0.2s;
  display: inline-block;
  line-height: 1;
}

.cms-menu__arrow--open {
  transform: rotate(180deg);
}

/* Desktop dropdown — hidden, shown ONLY via .--open class (click-based) */
.cms-menu__sub {
  display: none;
  position: absolute;
  top: calc(100% + 6px);
  left: 0;
  background: var(--color-surface, #ffffff);
  border: 1px solid var(--color-border, #e2e8f0);
  border-radius: 8px;
  padding: 0.375rem 0;
  min-width: 190px;
  z-index: 300;
  box-shadow: 0 8px 24px rgba(0,0,0,0.1);
  list-style: none;
}

.cms-menu__sub--open {
  display: block;
}

.cms-menu__sub .cms-menu__link {
  padding: 0.5rem 1rem;
  font-size: 0.9rem;
  font-weight: 400;
}

.cms-menu__sub .cms-menu__link:hover {
  background: var(--color-surface, #f8fafc);
}

/* ── Burger button — hidden on desktop ───────────────────── */
.cms-burger {
  display: none;
  flex-direction: column;
  justify-content: center;
  gap: 5px;
  width: 40px;
  height: 40px;
  padding: 6px;
  background: transparent;
  border: none;
  cursor: pointer;
  border-radius: 6px;
  z-index: 400;
  flex-shrink: 0;
  color: inherit;
}

.cms-burger span {
  display: block;
  width: 100%;
  height: 2px;
  background: currentColor;
  border-radius: 2px;
  transition: transform 0.25s, opacity 0.2s;
  transform-origin: center;
}

.cms-burger--open span:nth-child(1) { transform: translateY(7px) rotate(45deg); }
.cms-burger--open span:nth-child(2) { opacity: 0; transform: scaleX(0); }
.cms-burger--open span:nth-child(3) { transform: translateY(-7px) rotate(-45deg); }

/* ── Overlay — hidden, shown on mobile open ──────────────── */
.cms-menu-overlay {
  display: none;
  position: fixed;
  inset: 0;
  background: rgba(0,0,0,0.45);
  z-index: 250;
  backdrop-filter: blur(2px);
}

.cms-menu-overlay--open {
  display: block;
}

/* ── Mobile ──────────────────────────────────────────────── */
@media (max-width: 768px) {
  .cms-burger {
    display: flex;
  }

  .cms-menu {
    position: fixed;
    top: 0;
    right: -100%;
    width: min(300px, 85vw);
    height: 100dvh;
    flex-direction: column;
    align-items: stretch;
    background: var(--color-bg, #ffffff);
    padding: 4.5rem 0 2rem;
    overflow-y: auto;
    z-index: 300;
    transition: right 0.28s cubic-bezier(0.4,0,0.2,1);
    box-shadow: -4px 0 24px rgba(0,0,0,0.15);
  }

  .cms-menu--open {
    right: 0;
  }

  .cms-menu__item {
    position: static;
    border-bottom: 1px solid var(--color-border, #e2e8f0);
  }

  .cms-menu__link {
    padding: 0.9rem 1.5rem;
    font-size: 1rem;
    justify-content: space-between;
  }

  /* Accordion sub-menu on mobile */
  .cms-menu__sub {
    position: static;
    display: block;
    max-height: 0;
    overflow: hidden;
    background: var(--color-surface, #f8fafc);
    border: none;
    border-radius: 0;
    box-shadow: none;
    padding: 0;
    transition: max-height 0.25s ease;
  }

  .cms-menu__sub--open {
    display: block;
    max-height: 400px;
  }

  .cms-menu__sub .cms-menu__item {
    border-bottom: 1px solid var(--color-border, #e2e8f0);
  }

  .cms-menu__sub .cms-menu__link {
    padding-left: 2.5rem;
    font-size: 0.9rem;
    opacity: 0.85;
  }
}
